function biquge() {
	    let disc = []
    let url = baseUrl.replaceAll(/[^\w]+$/gi, '');
  let tagHtml = java.ajax(`${url}/category.html`);
    let doc = org.jsoup.Jsoup.parse(tagHtml);
  let tags = doc.select(".tar a");
  Array.from(tags).forEach(a => {
     disc.push({
      title: String(a.ownText().trim()).replace(/查看所有|>>/g, ""),
      url: String(a.attr("href")).replace(/\/category\/([^\/]+)\.html$/, '/category/$1/{{page}}.html'),
      style: {
        layout_flexGrow: 1,
        layout_flexBasisPercent: 0.25
      }
    });
  });

  let taml = java.ajax(`${url}/top.html`);
    let dc = org.jsoup.Jsoup.parse(taml);
        let tas = dc.select(".topindex .card");
    Array.from(tas).forEach(x => {
        let name = x.select("h3").text(),
            link = x.select(".tar a").attr("href");
        disc.push({
            title: name,
            url: String(link).replace(/\/top\/([^\/]+)\.html$/, '/top/$1/{{page}}.html'),
            style: {
                layout_flexGrow: 1,
                layout_flexBasisPercent: 0.25
            }
        });
    });


  disc.push({
    title: "全本小说",
    url: "/over/{{page}}.html",
    style: {layout_flexGrow: 1, layout_flexBasisPercent: 0.25}
  },
  {
    title: "最近更新",
    url: "/top/lastupdate/{{page}}.html",
    style: {layout_flexBasisPercent: 1, layout_flexGrow: 1}
  });


      return JSON.stringify(disc);
}
